template<typename... Ts>
struct MaxSize {
    static constexpr size_t value = std::max({sizeof(Ts)...});
};

template<typename... Ts>
struct MaxAlign {
    static constexpr size_t value = std::max({alignof(Ts)...});
};

using Storage = std::aligned_storage_t<MaxSize<Ts...>::value, MaxAlign<Ts...>::value>;

template<typename T, typename... Ts>
struct TypeIndex;

template<typename T, typename First, typename... Rest>
struct TypeIndex<T, First, Rest...> {
    static constexpr size_t value = std::is_same_v<T, First> ? 0 : 1 + TypeIndex<T, Rest...>::value;
};

template<typename T>
struct TypeIndex<T> {
    static constexpr size_t value = 0;  // Will cause compile error if not found
};
